// Extrai os dados do body (multipart/form-data ou JSON)
const body = $input.first().json.body || {};

const content = body.content || '';
const etpContent = body.etp_content || 'Nenhum ETP fornecido.';
const matrizRiscos = body.matriz_riscos || 'Nenhuma Matriz de Risco fornecida.';
const processId = body.process_id || 'N/A';
const hasFile = body.has_file === 'true' || body.has_file === true;

return [{
  json: {
    content,
    etp_content: etpContent,
    matriz_riscos: matrizRiscos,
    process_id: processId,
    has_file: hasFile
  }
}];

// Tenta extrair texto do arquivo PDF se existir
const binaryData = $input.first().binary || {};
const baseData = $('Processa Payload').first().json;

// Verifica se veio algum arquivo
const fileKeys = Object.keys(binaryData);
let fileText = 'Nenhuma pesquisa de precos fornecida.';

if (fileKeys.length > 0) {
  // Se tem arquivo, o texto extraído virá pelo nó extractFromFile
  // Por ora, registramos que tem arquivo
  fileText = '[Arquivo recebido - ver nó de extração]';
}

return [{
  json: {
    ...baseData,
    pesquisa_precos_texto: fileText
  }
}];

function extractJSON(text) {
  if (!text || typeof text !== 'string') {
    if (typeof text === 'object' && text !== null) return text;
    return {};
  }
  try {
    const mdMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (mdMatch) return JSON.parse(mdMatch[1]);
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
  } catch (e) {}
  return { output_falho: text };
}

const baseData = $('Prepara Contexto').first().json;

const out1 = extractJSON($('Agente 1: Especificacoes e Custos').first()?.json?.output);
const out2 = extractJSON($('Agente 2: Requisitos Licitatorios').first()?.json?.output);
const out3 = extractJSON($('Agente 3: Riscos e Fiscalizacao').first()?.json?.output);

const previewRequisitos = out2.secao_requisitos_texto_preview || out2.output_falho || '';
const previewGestao = out3.secao_gestao_texto_preview || out3.output_falho || '';
const previewInfracoes = out3.secao_infracoes_texto_preview || '';

const docxData = {
  numero_processo: baseData.process_id || 'N/A',
  objeto_contratacao: out1.objeto_contratacao || 'N/A',
  prazo_entrega: out1.prazo_entrega || 'N/A',
  vigencia: out1.vigencia || 'N/A',
  is_bens_comuns: out2.is_bens_comuns !== undefined ? out2.is_bens_comuns : true,
  is_bens_especiais: out2.is_bens_especiais !== undefined ? out2.is_bens_especiais : false,
  aceita_subcontratacao: out2.aceita_subcontratacao !== undefined ? out2.aceita_subcontratacao : false,
  exige_garantia_contratual: out2.exige_garantia_contratual !== undefined ? out2.exige_garantia_contratual : false,
  exige_amostra: out2.exige_amostra !== undefined ? out2.exige_amostra : false,
  modalidade_licitacao: out2.modalidade_licitacao || 'Pregao Eletronico',
  prazo_garantia: out3.prazo_garantia || '12 meses',
  itens: Array.isArray(out1.itens) ? out1.itens : []
};

return [{
  json: {
    sucesso: true,
    frontend_preview: {
      secao_requisitos: previewRequisitos,
      secao_gestao: previewGestao,
      secao_infracoes: previewInfracoes
    },
    docxtemplater: docxData
  }
}];
